long		gLoadingStartTime	= 0;Sound		gSelectSound		= NULL;Sound		gClickSound			= NULL;Sound		gHealSound			= NULL;Sound		gLevelUpSound		= NULL;Sound		gGetTreasureSound	= NULL;Sound		gBattleHitSound		= NULL;Sound		gBattleDinkSound	= NULL;Sound		gBattleMissSound	= NULL;Sound		gBattleDeathSound	= NULL;Sound		gBattleCastSound	= NULL;Sound		g1PathSound			= NULL;Sound		g2HitSound			= NULL;Sound		g3PathSound			= NULL;Sound		g3HitSound			= NULL;Sound		g4PathSound			= NULL;Sound		g4HitSound			= NULL;Sound		g5HitSound			= NULL;PicturePtr	gSelectButton		= NULL;PicturePtr	gNotSelectButton	= NULL;short		gSelectButtonX		= -1;short		gSelectButtonY		= -1;Boolean		gSelectButtonFlag	= false;Boolean		gIsRegistered		= false;//*************************************************************************************//  internal function declerations//*************************************************************************************pascal OSStatus	DragonAlphaMainEventHandler		(EventHandlerCallRef	myHandler,												EventRef				event,												void *					userData);pascal OSStatus	DragonAlphaAboutEventHandler	(EventHandlerCallRef	myHandler,												EventRef				event,												void *					userData);//*************************************************************************************//  main//*************************************************************************************int main(int argc, char * argv[]){	// Install	InstallBasics();	//TurnDebugOn();		CheckSystem();	InstallDragonAlpha();	InstallGraphics(kScreenWidth, kScreenHeight, kScreenDepth);	InstallQuickTime();	InstallDragonAlphaPostJNP();		// Install UI	GetGWorld(&gOldPort);	SetPortWindowPort(gMainWindow);	PicturePtr dracosoftScreen;	error = GetPicture(kDracosoftScreen, &dracosoftScreen);	error = DrawPicture(dracosoftScreen);	error = DisposePicture(dracosoftScreen);	if(QDIsPortBuffered(GetWindowPort(gMainWindow)) == true)		QDFlushPortBuffer(GetWindowPort(gMainWindow), NULL);	SetLoadTime(kStartupLoadTime);	DrawLoad(-1, 236, 500);	Load();		// Install Other	InstallDragonAlphaSounds();	Load();	InstallBMusic(kThemeMusic);	Load();	InstallStartMode();	Load();	InstallMapMode(gMainWindow);	Load();	InstallBattleMode(gMainWindow);	Load();		// Install Handlers	InstallDragonAlphaHandlers();	Load();	InstallQuickTimeHandlers();	Load();	InstallStartModeHandlers(gMainWindow);	Load();		// Install Finish	FinishLoad();	DrawStartMode();		// Run	RunApplicationEventLoop();		// Uninstall	SetPortWindowPort(gMainWindow);	error = GetPicture(kDracosoftScreen, &dracosoftScreen);	error = DrawPicture(dracosoftScreen);	error = DisposePicture(dracosoftScreen);	if(QDIsPortBuffered(GetWindowPort(gMainWindow)) == true)		QDFlushPortBuffer(GetWindowPort(gMainWindow), NULL);	Delay(60, 0);	UninstallBattleMode();	UninstallMapMode();	UninstallStartMode();	UninstallBMusic();	UninstallQuickTime();	UninstallGraphics();	UninstallDragonAlpha();		return noErr;}//*************************************************************************************//  Dragon Alpha functions//*************************************************************************************void CheckSystem (void){	long response;	error = Gestalt(gestaltSystemVersion, &response);	if(response < 0x0860)	{		NonFatalError("\pYou must be running System 8.6 or newer!");		if(GetKeys() != aKey)			ExitToShell();	}	if(response >= 0x1000)		gIsOSX = true;	error = Gestalt(gestaltPhysicalRAMSize, &response);	if(response < 67108864)	{		NonFatalError("\pYou must have 64MB of RAM or more!");		ExitToShell();	}	error = Gestalt(gestaltCarbonVersion, &response);	if(response < 0x0110)	{		NonFatalError("\pYou must be running Carbon 1.1 or newer!");		ExitToShell();	}}void InstallDragonAlpha (void){	IBNibRef nibRef;	error = CreateNibReference(CFSTR("Dragon Alpha"), &nibRef);	ErrorCheck(error, "\pDragonAlpha:InstallDragonAlpha:CreateNibReference");	if(gIsOSX)	{		error = SetMenuBarFromNib(nibRef, CFSTR("MainMenu"));		ErrorCheck(error, "\pDragonAlpha:InstallDragonAlpha:SetMenuBarFromNib");	}	else	{		error = SetMenuBarFromNib(nibRef, CFSTR("ClassicMenu"));		ErrorCheck(error, "\pDragonAlpha:InstallDragonAlpha:SetMenuBarFromNib");	}	error = CreateWindowFromNib(nibRef, CFSTR("MainWindow"), &gMainWindow);	ErrorCheck(error, "\pDragonAlpha:InstallDragonAlpha:CreateWindowFromNib");	error = CreateWindowFromNib(nibRef, CFSTR("XAboutBox"), &gAboutBoxWindow);	ErrorCheck(error, "\pDragonAlpha:InstallDragonAlpha:CreateWindowFromNib");	DisposeNibReference(nibRef);	if(QDIsPortBuffered(GetWindowPort(gMainWindow)) == false)	{		error = GetPicture(kStartScreenUI, &gWindowBuffer);		ErrorCheck(error, "\pDragonAlpha:InstallDragonAlpha:GetPicture");	}	error = GetPicture(kLoadingPicture1, &gLoadingBar[0]);	ErrorCheck(error, "\pDragonAlpha:InstallDragonAlpha:GetPicture");	error = GetPicture(kLoadingPicture2, &gLoadingBar[1]);	ErrorCheck(error, "\pDragonAlpha:InstallDragonAlpha:GetPicture");	error = GetPicture(kLoadingPicture3, &gLoadingBar[2]);	ErrorCheck(error, "\pDragonAlpha:InstallDragonAlpha:GetPicture");	error = GetPicture(kLoadingColor, &gLoadingColor);	ErrorCheck(error, "\pDragonAlpha:InstallDragonAlpha:GetPicture");		error = GetPicture(kSelectButton, &gSelectButton);	ErrorCheck(error, "\pDragonAlpha:InstallDragonAlpha:GetPicture");	error = GetPicture(kNotSelectButton, &gNotSelectButton);	ErrorCheck(error, "\pDragonAlpha:InstallDragonAlpha:GetPicture");}void InstallDragonAlphaPostJNP (void){	Boolean sound;	Boolean music;	Boolean screen;	GetPreferences(&sound, &music, &screen, NULL, NULL);	if(sound == false)		ToggleSound();	if(music == false)		ToggleMusic();	if(screen == true)		ToggleFullScreenOn();	else	{		ShowWindow(gMainWindow);		SelectWindow(gMainWindow);	}}void InstallDragonAlphaSounds (void){	GetSound(kSelectSound, &gSelectSound);	GetSound(kClickSound, &gClickSound);	GetSound(kHealSound, &gHealSound);	GetSound(kLevelUpSound, &gLevelUpSound);	GetSound(kGetTreasureSound, &gGetTreasureSound);	GetSound(kBattleHitSound, &gBattleHitSound);	GetSound(kBattleDinkSound, &gBattleDinkSound);	GetSound(kBattleMissSound, &gBattleMissSound);	GetSound(kBattleDeathSound, &gBattleDeathSound);	GetSound(kBattleCastSound, &gBattleCastSound);		GetSound(k1PathSound, &g1PathSound);	GetSound(k2HitSound, &g2HitSound);	GetSound(k3PathSound, &g3PathSound);	GetSound(k3HitSound, &g3HitSound);	GetSound(k4PathSound, &g4PathSound);	GetSound(k4HitSound, &g4HitSound);	GetSound(k5HitSound, &g5HitSound);}void InstallDragonAlphaHandlers (void){	EventTypeSpec mainSpec = {kEventClassCommand, kEventCommandProcess};	error = InstallApplicationEventHandler(NewEventHandlerUPP(DragonAlphaMainEventHandler), 1, &mainSpec, NULL, NULL);	ErrorCheck(error, "\pDragonAlpha:InstallDragonAlphaHandlers:InstallApplicationEventHandler");		EventTypeSpec aboutSpec = {kEventClassWindow, kEventWindowClose};	error = InstallWindowEventHandler(gAboutBoxWindow, NewEventHandlerUPP(DragonAlphaAboutEventHandler), 1, &aboutSpec, NULL, NULL);	ErrorCheck(error, "\pDragonAlpha:InstallDragonAlphaHandlers:InstallWindowEventHandler");}void UninstallDragonAlpha (void){	DisposePicture(gLoadingBar[0]);	DisposePicture(gLoadingBar[1]);	DisposePicture(gLoadingBar[2]);	DisposePicture(gLoadingColor);		DisposeSound(gSelectSound);	DisposeSound(gClickSound);	DisposeSound(gHealSound);	DisposeSound(gLevelUpSound);	DisposeSound(gGetTreasureSound);	DisposeSound(gBattleHitSound);	DisposeSound(gBattleDinkSound);	DisposeSound(gBattleMissSound);	DisposeSound(gBattleDeathSound);	DisposeSound(gBattleCastSound);		DisposePicture(gSelectButton);	DisposePicture(gNotSelectButton);	DisposePicture(gWindowBuffer);}Boolean IsOSX (void){	return gIsOSX;}//*************************************************************************************//  Menu functions//*************************************************************************************void AboutDragonAlpha (void){	ShowWindow(gAboutBoxWindow);	SelectWindow(gAboutBoxWindow);}void Registration (void){	}void NewGame (void){	if(InstallCharacter() == false)		return;	SetPortWindowPort(gMainWindow);	Boolean isCorePlug = MapWarpAction(1, 128, 25, 23, true);	if(isCorePlug == false)		return;	UninstallStartModeHandlers();	UninstallMapModeHandlers();	InstallMapModeHandlers(gMainWindow);}void OpenGame (void){	if(OpenCharacter() == false)		return;	SetPortWindowPort(gMainWindow);	short plugID = GetCharPlugID();	SetCharPlugID(0);	Boolean plug = MapWarpAction(plugID, GetCharMapID(), GetCharMapPositionX() / 32, GetCharMapPositionY() / 32, true);	if(plug == false)		return;	UninstallStartModeHandlers();	UninstallMapModeHandlers();	InstallMapModeHandlers(gMainWindow);}void ToggleSoundOn (void){	ToggleSound();	if(IsSoundOn() == true)	{		Boolean True = true;		SetPreferences(&True, NULL, NULL, NULL, NULL);	}	else	{		Boolean False = false;		SetPreferences(&False, NULL, NULL, NULL, NULL);	}}void ToggleMusicOn (void){	ToggleMusic();	if(IsMusicOn() == true)	{		Boolean True = true;		SetPreferences(NULL, &True, NULL, NULL, NULL);	}	else	{		Boolean False = false;		SetPreferences(NULL, &False, NULL, NULL, NULL);	}}void ToggleFullScreenOn (void){	error = ToggleFullScreen(gMainWindow);	ErrorCheck(error, "\pDragonAlpha:ToggleFullScreenOn:ToggleFullScreen");	if(IsFullScreenOn() == true)	{		Boolean True = true;		SetPreferences(NULL, NULL, &True, NULL, NULL);	}	else	{		Boolean False = false;		SetPreferences(NULL, NULL, &False, NULL, NULL);	}}Boolean QuitGame (void){	if(YesNoError("\pAre you sure you want to quit Dragon Alpha?") == true)		QuitApplicationEventLoop();	return true;}//*************************************************************************************//  Loading Bar functions//*************************************************************************************void DrawLoad (short perc, short x, short y){	if(perc < 0)	{		gLoadingX = x;		gLoadingY = y;		Rect rect;		GetPortBounds(gLoadingBar[0], &rect);		SetRectRgn(gLoadingRgn, rect.left, rect.top, rect.right, rect.bottom);		DrawPicture(gLoadingBar[0], x, y);	}	else if(perc >= 100)		DrawPicture(gLoadingBar[2], x, y);	else	{		error = DrawPicture(gLoadingBar[1], x, y);		Rect dstRect;		GetPortBounds(gLoadingColor, &dstRect);		dstRect.right += ((269 * perc) / 100) - 3;		OffsetRect(&dstRect, x + 52, y + 34);		DrawPicture(gLoadingColor, &dstRect);	}	if(QDIsPortBuffered(GetWindowPort(GameWindow())) == true)		QDFlushPortBuffer(GetWindowPort(GameWindow()), gLoadingRgn);}void SetLoadTime (long ticks){	gLoadingTime		= ticks;	gLoadingStartTime	= TickCount();}void Load (void){	if(TickCount() - gLoadingStartTime < gLoadingTime)		DrawLoad(((TickCount() - gLoadingStartTime) * 100) / gLoadingTime, gLoadingX, gLoadingY);	else	{		SetLoadTime(gLoadingTime / 4);		DrawLoad(0, gLoadingX, gLoadingY);	}}void FinishLoad (void){	while(TickCount() - gLoadingStartTime < gLoadingTime)		DrawLoad(((TickCount() - gLoadingStartTime) * 100) / gLoadingTime, gLoadingX, gLoadingY);	DrawLoad(100, gLoadingX, gLoadingY);}//*************************************************************************************//  Sound functions//*************************************************************************************void PlaySelectSound (void){	PlaySound(gSelectSound);}void PlayClickSound (void){	PlaySound(gClickSound);}void PlayHealSound (void){	PlaySound(gHealSound);}void PlayLevelUpSound (void){	PlaySound(gLevelUpSound);}void PlayGetTreasureSound (void){	PlaySound(gGetTreasureSound);}void PlayBattleHitSound (void){	PlaySound(gBattleHitSound);}void PlayBattleDinkSound (void){	PlaySound(gBattleDinkSound);}void PlayBattleMissSound (void){	PlaySound(gBattleMissSound);}void PlayBattleHealSound (void){	PlayHealSound();}void PlayBattleDeathSound (void){	PlaySound(gBattleDeathSound);}void PlayBattleCastSound (void){	PlaySound(gBattleCastSound);}void PlayBattlePathSound (short sound){	switch(sound)	{		case 0:			break;		case 1:			PlaySound(g1PathSound);			break;		case 2:			break;		case 3:			PlaySound(g3PathSound);			break;		case 4:			PlaySound(g4PathSound);			break;		case 5:			break;	}}void PlayBattleHitSound (short sound){	switch(sound)	{		case 0:			PlayBattleHitSound();			break;		case 1:			break;		case 2:			PlaySound(g2HitSound);			break;		case 3:			PlaySound(g3HitSound);			break;		case 4:			PlaySound(g4HitSound);			break;		case 5:			PlaySound(g5HitSound);			break;	}}//*************************************************************************************//  Common Picture functions//*************************************************************************************void DrawSelectButton (short x, short y, Boolean selected){	if(selected == true)	{		if(x != gSelectButtonX || y != gSelectButtonY || gSelectButtonFlag != true)		{			PlaySelectSound();			DrawPicture(gSelectButton, x, y);			gSelectButtonX = x;			gSelectButtonY = y;			gSelectButtonFlag = true;		}	}	else	{		if(x != gSelectButtonX || y != gSelectButtonY || gSelectButtonFlag != false)		{			DrawPicture(gNotSelectButton, x, y);			gSelectButtonX = x;			gSelectButtonY = x;			gSelectButtonFlag = false;		}	}}WindowRef GameWindow (void){	return gMainWindow;}CGrafPtr OldWindow (void){	return gOldPort;}CGrafPtr GameBuffer (void){	return gWindowBuffer;}//*************************************************************************************//  Preferences functions//*************************************************************************************void GetPreferences (Boolean * isSoundOn, Boolean * isMusicOn, Boolean * isFullScreenOn, Str255 * myRegName, Str255 * myRegNumber){	if(isSoundOn != NULL)	{		CFStringRef isSoundOnKey = CFSTR(kPreferencesSoundKey);		CFStringRef isSoundOnStr = (CFStringRef)CFPreferencesCopyAppValue(isSoundOnKey, kCFPreferencesCurrentApplication);		if(isSoundOnStr == NULL)			*isSoundOn = true;		else		{			Str255 string;			CFStringGetPascalString((CFStringRef)isSoundOnStr, string, 256, 0);			if(pstrcmp(string, "\ptrue") == 0)				*isSoundOn = true;			else				*isSoundOn = false;		}	}	if(isMusicOn != NULL)	{		CFStringRef isMusicOnKey = CFSTR(kPreferencesMusicKey);		CFStringRef isMusicOnStr = (CFStringRef)CFPreferencesCopyAppValue(isMusicOnKey, kCFPreferencesCurrentApplication);		if(isMusicOnStr == NULL)			*isMusicOn = true;		else		{			Str255 string;			CFStringGetPascalString((CFStringRef)isMusicOnStr, string, 256, 0);			if(pstrcmp(string, "\ptrue") == 0)				*isMusicOn = true;			else				*isMusicOn = false;		}	}	if(isFullScreenOn != NULL)	{		CFStringRef isFullScreenOnKey = CFSTR(kPreferencesScreenKey);		CFStringRef isFullScreenOnStr = (CFStringRef)CFPreferencesCopyAppValue(isFullScreenOnKey, kCFPreferencesCurrentApplication);		if(isFullScreenOnStr == NULL)			*isFullScreenOn = false;		else		{			Str255 string;			CFStringGetPascalString((CFStringRef)isFullScreenOnStr, string, 256, 0);			if(pstrcmp(string, "\ptrue") == 0)				*isFullScreenOn = true;			else				*isFullScreenOn = false;		}	}	if(myRegName != NULL)	{		CFStringRef regNameKey = CFSTR(kPreferencesRegNameKey);		CFStringRef regName = (CFStringRef)CFPreferencesCopyAppValue(regNameKey, kCFPreferencesCurrentApplication);		if(regName == NULL)			pstrcpy(*myRegName, "\p");		else			CFStringGetPascalString((CFStringRef)regName, *myRegName, 256, 0);	}	if(myRegNumber != NULL)	{		CFStringRef regNumberKey = CFSTR(kPreferencesRegNumberKey);		CFStringRef regNumber = (CFStringRef)CFPreferencesCopyAppValue(regNumberKey, kCFPreferencesCurrentApplication);		if(regNumber == NULL)			pstrcpy(*myRegNumber, "\p");		else			CFStringGetPascalString((CFStringRef)regNumber, *myRegNumber, 256, 0);	}}void SetPreferences (Boolean * isSoundOn, Boolean * isMusicOn, Boolean * isFullScreenOn, Str255 * myRegName, Str255 * myRegNumber){	if(isSoundOn != NULL)	{		CFStringRef isSoundOnKey = CFSTR(kPreferencesSoundKey);		if(*isSoundOn == true)			CFPreferencesSetAppValue(isSoundOnKey, CFSTR("true"), kCFPreferencesCurrentApplication);		else			CFPreferencesSetAppValue(isSoundOnKey, CFSTR("false"), kCFPreferencesCurrentApplication);	}	if(isMusicOn != NULL)	{		CFStringRef isMusicOnKey = CFSTR(kPreferencesMusicKey);		if(*isMusicOn == true)			CFPreferencesSetAppValue(isMusicOnKey, CFSTR("true"), kCFPreferencesCurrentApplication);		else			CFPreferencesSetAppValue(isMusicOnKey, CFSTR("false"), kCFPreferencesCurrentApplication);	}	if(isFullScreenOn != NULL)	{		CFStringRef isFullScreenOnKey = CFSTR(kPreferencesScreenKey);		if(*isFullScreenOn == true)			CFPreferencesSetAppValue(isFullScreenOnKey, CFSTR("true"), kCFPreferencesCurrentApplication);		else			CFPreferencesSetAppValue(isFullScreenOnKey, CFSTR("false"), kCFPreferencesCurrentApplication);	}	if(myRegName != NULL)	{		CFStringRef regName = CFSTR(kPreferencesRegNameKey);		char cStr[255];		CopyPascalStringToC(*myRegName, cStr);		CFPreferencesSetAppValue(regName, __CFStringMakeConstantString(cStr), kCFPreferencesCurrentApplication);	}	if(myRegNumber != NULL)	{		CFStringRef regNumber = CFSTR(kPreferencesRegNumberKey);		char cStr[255];		CopyPascalStringToC(*myRegNumber, cStr);		CFPreferencesSetAppValue(regNumber, __CFStringMakeConstantString(cStr), kCFPreferencesCurrentApplication);	}	CFPreferencesAppSynchronize(kCFPreferencesCurrentApplication);}void GetRegPref (short plugID, Str255 * name, Str255 * number){	CFStringRef regNameKey;	CFStringRef regName;	CFStringRef regNumberKey;	CFStringRef regNumber;	switch(plugID)	{		case 0:			regNameKey = CFSTR(kPreferencesRegNameKey);			regName = (CFStringRef)CFPreferencesCopyAppValue(regNameKey, kCFPreferencesCurrentApplication);			if(regName == NULL)				pstrcpy(*name, "\p");			else				CFStringGetPascalString((CFStringRef)regName, *name, 256, 0);			regNumberKey = CFSTR(kPreferencesRegNumberKey);			regNumber = (CFStringRef)CFPreferencesCopyAppValue(regNumberKey, kCFPreferencesCurrentApplication);			if(regNumber == NULL)				pstrcpy(*number, "\p");			else				CFStringGetPascalString((CFStringRef)regNumber, *number, 256, 0);			break;		case kTheMeadowsPlug:			regNameKey = CFSTR("DA-1000Name");			regName = (CFStringRef)CFPreferencesCopyAppValue(regNameKey, kCFPreferencesCurrentApplication);			if(regName == NULL)				pstrcpy(*name, "\p");			else				CFStringGetPascalString((CFStringRef)regName, *name, 256, 0);			regNumberKey = CFSTR("DA-1000Number");			regNumber = (CFStringRef)CFPreferencesCopyAppValue(regNumberKey, kCFPreferencesCurrentApplication);			if(regNumber == NULL)				pstrcpy(*number, "\p");			else				CFStringGetPascalString((CFStringRef)regNumber, *number, 256, 0);			break;		default:			pstrcpy(*name, "\p");			pstrcpy(*number, "\p");			break;	}}void SetRegPref (Str255 * name, Str255 * number){	Str255 code;	pstrcpy(code, *number);	code[0] = 7;	if(pstrcmp(code, "\pDA-0000") == 0) // Dragon Alpha	{		CFStringRef regName = CFSTR(kPreferencesRegNameKey);		char cStr[255];		CopyPascalStringToC(*name, cStr);		CFPreferencesSetAppValue(regName, __CFStringMakeConstantString(cStr), kCFPreferencesCurrentApplication);		CFStringRef regNumber = CFSTR(kPreferencesRegNumberKey);		CopyPascalStringToC(*number, cStr);		CFPreferencesSetAppValue(regNumber, __CFStringMakeConstantString(cStr), kCFPreferencesCurrentApplication);		CFPreferencesAppSynchronize(kCFPreferencesCurrentApplication);	}	else if(pstrcmp(code, "\pDA-1000") == 0) // The Meadows Plug	{		CFStringRef regName = CFSTR("DA-1000Name");		char cStr[255];		CopyPascalStringToC(*name, cStr);		CFPreferencesSetAppValue(regName, __CFStringMakeConstantString(cStr), kCFPreferencesCurrentApplication);		CFStringRef regNumber = CFSTR("DA-1000Number");		CopyPascalStringToC(*number, cStr);		CFPreferencesSetAppValue(regNumber, __CFStringMakeConstantString(cStr), kCFPreferencesCurrentApplication);		CFPreferencesAppSynchronize(kCFPreferencesCurrentApplication);	}}//*************************************************************************************//  Plug-In functions//*************************************************************************************void GetPlugInPath (short plugID, Str255 * outPlugPath){	switch(plugID)	{		case kCorePlug:			pstrcpy(*outPlugPath, "\p::::Plug-Ins:Core Plug 1.1.app:Contents:");			break;		case kCavesPlug:			pstrcpy(*outPlugPath, "\p::::Plug-Ins:Caves Plug 1.1.app:Contents:");			break;		case kMountainPlug:			pstrcpy(*outPlugPath, "\p::::Plug-Ins:Mountain Plug 1.1.app:Contents:");			break;		case kForestPlug:			pstrcpy(*outPlugPath, "\p::::Plug-Ins:Forest Plug 1.1.app:Contents:");			break;		case kTitaniumPlug:			pstrcpy(*outPlugPath, "\p::::Plug-Ins:Titanium Plug 1.1.app:Contents:");			break;		case kGoblinPlug:			pstrcpy(*outPlugPath, "\p::::Plug-Ins:Goblin Plug 1.1.app:Contents:");			break;		case kTheMeadowsPlug:			pstrcpy(*outPlugPath, "\p::::Plug-Ins:The Meadows Plug 1.1.app:Contents:");			break;		default:			pstrcpy(*outPlugPath, "\p");			break;	}}void GetPlugInName (short plugID, Str255 * outName){	switch(plugID)	{		case kCorePlug:			pstrcpy(*outName, "\pCore Plug 1.1");			break;		case kCavesPlug:			pstrcpy(*outName, "\pCaves Plug 1.1");			break;		case kMountainPlug:			pstrcpy(*outName, "\pMountain Plug 1.1");			break;		case kForestPlug:			pstrcpy(*outName, "\pForest Plug 1.1");			break;		case kTitaniumPlug:			pstrcpy(*outName, "\pTitanium Plug 1.1");			break;		case kGoblinPlug:			pstrcpy(*outName, "\pGoblin Plug 1.1");			break;		case kTheMeadowsPlug:			pstrcpy(*outName, "\pThe Meadows Plug 1.1");			break;		default:			pstrcpy(*outName, "\pUnkown Plug");			break;	}	}void BeginPlugUseResourceFile (short plugID){	Str255 path;	GetPlugInPath(plugID, &path);	pstrcat(path, "\pData");	error = BeginUseResourceFile(path);	ErrorCheck(error, "\pDragonAlpha:BeginPlugUseResourceFile:BeginUseResourceFile");}void EndPlugUseResourceFile (void){	error = EndUseResourceFile();	ErrorCheck(error, "\pDragonAlpha:EndPlugUseResourceFile:EndUseResourceFile");}//*************************************************************************************//  internal functions//*************************************************************************************pascal OSStatus DragonAlphaMainEventHandler (EventHandlerCallRef myHandler, EventRef event, void * userData){	OSStatus	result		= eventNotHandledErr;	HICommand	command;	error = GetEventParameter(event, kEventParamDirectObject, typeHICommand, NULL, sizeof(HICommand), NULL, &command);	ErrorCheck(error, "\pDragonAlpha:DragonAlphaMainEventHandler:GetEventParameter");	switch(command.commandID)	{		case kDAAboutDragonAlphaCommand:			AboutDragonAlpha();			result = noErr;			break;		case kDARegistrationCommand:			Registration();			result = noErr;			break;		case kDANewGameCommand:			NewGame();			result = noErr;			break;		case kDAOpenGameCommand:			OpenGame();			result = noErr;			break;		case kDAToggleSoundCommand:			ToggleSoundOn();			result = noErr;			break;		case kDAToggleMusicCommand:			ToggleMusicOn();			result = noErr;			break;		case kDAToggleFullScreenCommand:			ToggleFullScreenOn();			result = noErr;			break;	}	return result;}pascal OSStatus DragonAlphaAboutEventHandler (EventHandlerCallRef myHandler, EventRef event, void * userData){	OSStatus	result		= eventNotHandledErr;	UInt32		eventKind	= GetEventKind(event);	switch(eventKind)	{		case kEventWindowClose:			HideWindow(gAboutBoxWindow);			result = noErr;			break;	}	return result;}